# Protein translation

def parse_codon_table(filepath):
    """Parse a codon table file with format: 'CODON AA' or 'CODON' for stop codons."""
    codon_table = {}
    with open(filepath, 'r') as f:
        for line in f:
            parts = line.strip().split()
            if len(parts) == 2:
                codon_table[parts[0]] = parts[1]  # Regular codon
            elif len(parts) == 1:
                codon_table[parts[0]] = ""         # Stop codon
    return codon_table


def translate_rna_to_aa_string(rna_string, codon_table):
    """Translate an RNA string into an amino acid string."""
    aa_string = ""
    for i in range(0, len(rna_string), 3):
        codon = rna_string[i:i+3]
        if len(codon) < 3:
            break  # Ignore incomplete codons
        aa = codon_table.get(codon, '?')
        if aa == "":
            break  # Stop codon reached
        aa_string += aa

    return aa_string


codon_table = parse_codon_table("bioinfo_genome_sequencing/datasets/RNA_codon_table_1.txt")
rna = ""
print(translate_rna_to_aa_string(rna, codon_table))